import { ensureElement } from '../../utils/utils';
import { ComponentView } from '../base/ComponentView';
export var ModalWrapperEvents;
(function (ModalWrapperEvents) {
    ModalWrapperEvents["CloseButtonClicked"] = "modalButton:clicked";
})(ModalWrapperEvents || (ModalWrapperEvents = {}));
export class ModalWrapperView extends ComponentView {
    constructor(container, events, page) {
        super(container);
        this.closeButton = ensureElement('.modal__close', this.container);
        this.contentElement = ensureElement('.modal__content', this.container);
        this.events = events;
        this.page = page;
        this.closeButton.addEventListener('click', () => {
            this.events.emit(ModalWrapperEvents.CloseButtonClicked);
        });
        // Обработчик клика по фону (оверлею)
        this.container.addEventListener('click', (event) => {
            // Если клик по самому контейнеру, а не по внутреннему контенту
            if (event.target === this.container) {
                this.events.emit(ModalWrapperEvents.CloseButtonClicked);
            }
        });
    }
    insertContentAndDisplay(content) {
        this.contentElement.replaceChildren(content);
        this.container.classList.add('modal_active');
        this.page.classList.add('page__wrapper_locked');
    }
    closemodalWrapperAndClear() {
        this.container.classList.remove('modal_active');
        this.contentElement.innerHTML = '';
        this.page.classList.remove('page__wrapper_locked');
    }
}
