import { ComponentView } from '../base/ComponentView';
import { ensureElement } from '../../utils/utils';
export class FormView extends ComponentView {
    constructor(container, events) {
        super(container);
        this.form = this.container;
        if (!this.form) {
            console.log('Форма не найдена');
        }
        this.formErrors = ensureElement('.form__errors', this.form);
        if (!this.formErrors) {
            console.log('Элемент ошибок не найден');
        }
        this.events = events;
        if (!this.events) {
            console.log('Объект событий не найден');
        }
        this.form.setAttribute('novalidate', '');
        this.form.addEventListener('submit', (evt) => {
            evt.preventDefault();
        });
    }
    set spanErrors(text) {
        this.formErrors.textContent = text;
    }
    set buttonState(active) {
        if (active) {
            this.submitButton.removeAttribute('disabled');
        }
        else {
            this.submitButton.setAttribute('disabled', '');
        }
    }
}
