import { FormView } from './FormView';
export var ContactsFormEvents;
(function (ContactsFormEvents) {
    ContactsFormEvents["EmailInputChanged"] = "emailInput:changed";
    ContactsFormEvents["PhoneInputChanged"] = "phoneInput:changed";
    ContactsFormEvents["Submit"] = "contactsForm:submit";
})(ContactsFormEvents || (ContactsFormEvents = {}));
export class ContactsFormView extends FormView {
    constructor(container, events) {
        super(container, events);
        this.emailInput = this.form.querySelector('input[name="email"]');
        this.phoneInput = this.form.querySelector('input[name="phone"]');
        this.submitButton = this.form.querySelector('.contacts__button');
        if (this.emailInput) {
            this.emailInput.addEventListener('input', () => {
                this.events.emit(ContactsFormEvents.EmailInputChanged, {
                    email: this.emailInput.value,
                });
            });
        }
        else {
            console.log('emailInput не найден, событие input ContactsFormEvents.EmailInputChanged не эмитировано');
        }
        if (this.phoneInput) {
            this.phoneInput.addEventListener('input', () => {
                this.events.emit(ContactsFormEvents.PhoneInputChanged, {
                    phone: this.phoneInput.value,
                });
            });
        }
        else {
            console.log('phoneInput не найден, событие input ContactsFormEvents.PhoneInputChanged не эмитировано');
        }
        if (this.form) {
            this.form.addEventListener('submit', () => {
                this.events.emit(ContactsFormEvents.Submit, {
                    email: this.emailInput.value,
                    phone: this.phoneInput.value,
                });
            });
        }
        else {
            console.log('Форма не найдена, событие submit ContactsFormEvents.Submit не эмитировано');
        }
    }
    clearForm() {
        this.form.reset();
    }
}
